// ═══════════════════════════════════════════════════════════════════════════════
// Public Types — react-data-grid types do not leak through this boundary
// ═══════════════════════════════════════════════════════════════════════════════

export type HarmonySortDirection = 'ASC' | 'DESC'

export interface HarmonySortColumn {
  columnKey: string          // always the column key — used by DataGrid sort indicator
  direction: HarmonySortDirection
  /** API sort field name (from HarmonyColumn.sortParam, or falls back to columnKey). Use this for the API call. */
  sortParam?: string
}

export interface HarmonyRenderCellProps<TRow> {
  row: TRow
  rowIdx: number
}

export interface HarmonyRenderSummaryCellProps<TSummaryRow> {
  row: TSummaryRow
}

export interface HarmonyRenderEditCellProps<TRow> {
  row: TRow
  rowIdx: number
  onRowChange: (row: TRow, commit?: boolean) => void
  onClose: (commit?: boolean) => void
}

/**
 * Column definition for HarmonyTable.
 * Mirrors react-data-grid Column but uses harmony-specific render prop signatures.
 */
export interface HarmonyColumn<TRow, TSummaryRow = unknown> {
  key: string
  header: string | ReactElement
  width?: number | string
  /**
   * Fills remaining horizontal space after all fixed-width columns are placed.
   * At most one fill column per table is recommended — multiple fill columns split the
   * remaining space equally, which rarely produces the intended layout.
   */
  fill?: boolean
  minWidth?: number
  maxWidth?: number
  frozen?: boolean
  /** Default: true (via defaultColumnOptions) */
  sortable?: boolean
  /** Default: true (via defaultColumnOptions) */
  resizable?: boolean
  draggable?: boolean
  sortDescendingFirst?: boolean
  /** API sort field name to send as the `sort` query param. Falls back to `key` when absent. */
  sortParam?: string
  cellClass?: string | ((row: TRow) => string | null | undefined)
  headerCellClass?: string
  summaryCellClass?: string | ((row: TSummaryRow) => string | null | undefined)
  renderCell?: (props: HarmonyRenderCellProps<TRow>) => ReactNode
  renderSummaryCell?: (props: HarmonyRenderSummaryCellProps<TSummaryRow>) => ReactNode
  /** When provided the column becomes editable */
  renderEditCell?: (props: HarmonyRenderEditCellProps<TRow>) => ReactNode
}

/**
 * Pagination configuration.
 * Omit `onPageChange` for client-side pagination (HarmonyTable manages page state).
 * Provide `onPageChange` for server-side pagination (caller manages rows).
 */
export interface HarmonyPagination {
  pageSize?: number
  pageSizeOptions?: number[]
  // Server-side: caller manages rows externally
  totalCount?: number
  /** Total pages from API response — use directly instead of computing. */
  totalPages?: number
  currentPage?: number
  /** From API response — drives Prev button disabled state without math. */
  hasPreviousPage?: boolean
  /** From API response — drives Next button disabled state without math. */
  hasNextPage?: boolean
  onPageChange?: (page: number) => void
  onPageSizeChange?: (pageSize: number) => void
}

export interface HarmonyAutoRefresh {
  enabled: boolean
  /** Current interval in seconds */
  interval: number
  /** Defaults to [10, 30, 60, 300]. Pass a single-item array to hide the picker. */
  intervalOptions?: number[]
  onToggle: (enabled: boolean) => void
  onIntervalChange?: (seconds: number) => void
}

/**
 * Data-action buttons rendered in the command bar.
 * Omit any key to hide that button — no explicit permission flags needed.
 */
export interface HarmonyDataActions {
  /** Primary create button (rightmost, default variant). */
  onCreate?: () => void
  createLabel?: string
  /** Manual reload button. Also acts as the trigger for auto-refresh ticks. */
  onReload?: () => void
  /** Shows a spinner on the reload button when true. */
  reloading?: boolean
  /** Auto-refresh toggle + interval picker. Calls onReload on each tick. */
  autoRefresh?: HarmonyAutoRefresh
  /** Export button (primary variant). */
  onExport?: () => void
  exportLabel?: string
  /** Escape hatch — rendered to the left of Export. */
  extra?: ReactNode
}

/**
 * Structured server-side filter definition.
 * HarmonyTable renders the filter UI automatically from this config.
 */
export interface FilterDef {
  /** Query param name sent to the API (e.g. "level", "active"). */
  param: string
  /** Human-readable label shown in the filter row. */
  label: string
  type: 'select' | 'text' | 'boolean'
  /** Required when type = 'select'. */
  options?: { value: string; label: string }[]
  placeholder?: string
  /** Initial filter value. */
  defaultValue?: string
}

export interface HarmonyTableProps<TRow, TSummaryRow = unknown> {
  rows: TRow[]
  columns: HarmonyColumn<TRow, TSummaryRow>[]
  /** Required — must return a stable, unique key per row. Used for selection, detail panel, and row identity after sort/filter. */
  rowKeyGetter: (row: TRow) => string | number

  // ── Identity row (title bar) ─────────────────────────────────────────────────
  title?: string
  description?: string
  /** Rendered to the left of the title in the identity row. */
  toolbarLeft?: ReactNode
  /** Rendered to the right of the title in the identity row. */
  toolbarRight?: ReactNode

  // ── Search / filter ─────────────────────────────────────────────────────────
  searchable?: boolean
  searchPlaceholder?: string
  /** Controlled search query — when provided, search is server-side */
  searchQuery?: string
  /** When provided, search is considered server-side (caller updates rows) */
  onSearchChange?: (query: string) => void
  /** Override the default client-side filter function */
  filterFn?: (rows: TRow[], query: string) => TRow[]
  /** Structured server-side filter definitions — HarmonyTable renders the filter UI automatically. */
  filterDefs?: FilterDef[]
  /** Controlled filter values keyed by FilterDef.param. If omitted, HarmonyTable manages state internally. */
  filterValues?: Record<string, string>
  /** Fires whenever any filter value changes. Callers use params to re-query the API. */
  onFilterChange?: (params: Record<string, string>) => void
  /** Milliseconds to debounce onSearchChange calls. Default: 300. Set 0 to disable. */
  searchDebounce?: number

  // ── Sorting ─────────────────────────────────────────────────────────────────
  /** Controlled sort state — when provided, sort is server-side */
  sortColumns?: HarmonySortColumn[]
  /** When provided, sort is server-side (caller updates rows) */
  onSortColumnsChange?: (cols: HarmonySortColumn[]) => void
  /** Override the default client-side sort function */
  sortFn?: (rows: TRow[], sortColumns: HarmonySortColumn[]) => TRow[]

  // ── Pagination ──────────────────────────────────────────────────────────────
  /** false = disabled | true = client defaults | object = configure */
  pagination?: HarmonyPagination

  // ── Row selection ────────────────────────────────────────────────────────────
  selectable?: boolean
  selectedRows?: ReadonlySet<string | number>
  onSelectedRowsChange?: (rows: Set<string | number>) => void
  isRowSelectionDisabled?: (row: TRow) => boolean

  // ── Summary rows ─────────────────────────────────────────────────────────────
  topSummaryRows?: TSummaryRow[]
  bottomSummaryRows?: TSummaryRow[]
  /** Recomputed on every filter/sort change — use this instead of the static props for client-side tables. */
  topSummaryRowsFn?: (filteredRows: TRow[]) => TSummaryRow[]
  bottomSummaryRowsFn?: (filteredRows: TRow[]) => TSummaryRow[]

  // ── Empty / loading / error ───────────────────────────────────────────────────
  noRowsFallback?: ReactNode
  emptyMessage?: string
  loading?: boolean
  /** When set, renders an error state inside the grid area (overrides empty state). */
  error?: string | Error

  // ── Inline editing ───────────────────────────────────────────────────────────
  onRowsChange?: (rows: TRow[], changedIndexes: number[]) => void

  // ── Row appearance ───────────────────────────────────────────────────────────
  // rowHeight?: number        // Disabled: row height is controlled by the theme density system (compact/comfortable/spacious). Kept for historical reference.
  // headerRowHeight?: number  // Disabled: same reason as rowHeight.
  // summaryRowHeight?: number // Disabled: same reason as rowHeight.
  rowClass?: (row: TRow, rowIdx: number) => string | null | undefined

  // ── Column dragging ──────────────────────────────────────────────────────────
  draggableColumns?: boolean
  onColumnsReorder?: (sourceKey: string, targetKey: string) => void

  // ── Cell events ───────────────────────────────────────────────────────────────
  onCellClick?: (row: TRow, columnKey: string) => void
  onCellDoubleClick?: (row: TRow, columnKey: string) => void

  // ── Command bar data actions ─────────────────────────────────────────────────
  /** Permanent data-action buttons in the command bar (create, reload, export…). */
  dataActions?: HarmonyDataActions

  // ── Selection actions (contextual, replaces data actions when rows selected) ──
  /** Rendered in the command bar right-side when ≥1 row is selected. */
  selectionActions?: (selectedKeys: ReadonlySet<string | number>) => ReactNode

  // ── Read-only mode ────────────────────────────────────────────────────────────
  /** Disables selection, inline editing, and selection actions globally */
  readonly?: boolean

  // ── Row detail panel ──────────────────────────────────────────────────────
  /** When provided, clicking/double-clicking a row opens a detail panel with the returned content. */
  renderRowDetail?: (row: TRow, onClose: () => void) => ReactNode
  /** Title shown in the detail panel header. */
  rowDetailTitle?: string | ((row: TRow) => string)
  /** 'sheet' renders a right-side drawer; 'dialog' renders a centered modal. Default: 'dialog'. */
  rowDetailVariant?: 'sheet' | 'dialog'
  /** Whether to open the detail on single click or double click. Default: 'dblclick'. */
  rowDetailTrigger?: 'click' | 'dblclick'

  // ── Built-in export ──────────────────────────────────────────────────────────
  /** Renders an Export button that downloads the current rows as JSON. */
  exportable?: boolean
  /** Filename for the built-in JSON export. Default: 'export.json'. */
  exportFilename?: string

  // ── Misc ─────────────────────────────────────────────────────────────────────
  className?: string
  gridClassName?: string
  // direction?: 'ltr' | 'rtl'       // Disabled: Harmony is LTR-only. Kept for historical reference in case RTL support is ever needed.
  // enableVirtualization?: boolean  // Disabled: react-data-grid virtualises by default and HarmonyTable sizes itself to all rows, so toggling this off has no meaningful use case here. Kept for historical reference.
}

// ═══════════════════════════════════════════════════════════════════════════════
// Internal utilities
// ═══════════════════════════════════════════════════════════════════════════════

// ── Client-side search (plain text fallback) ──────────────────────────────

function simpleFilterFn<TRow>(rows: TRow[], query: string): TRow[] {
  const q = query.trim().toLowerCase()
  if (!q) return rows
  return rows.filter(row =>
    Object.values(row as Record<string, unknown>).some(
      v => v != null && String(v).toLowerCase().includes(q),
    ),
  )
}

function defaultSortFn<TRow>(rows: TRow[], sortCols: HarmonySortColumn[]): TRow[] {
  return [...rows].sort((a, b) => {
    for (const { columnKey, direction } of sortCols) {
      const av = (a as Record<string, unknown>)[columnKey]
      const bv = (b as Record<string, unknown>)[columnKey]
      let cmp = 0
      if (av == null && bv == null) cmp = 0
      else if (av == null) cmp = 1
      else if (bv == null) cmp = -1
      else if (typeof av === 'number' && typeof bv === 'number') cmp = av - bv
      else cmp = String(av).localeCompare(String(bv))
      if (cmp !== 0) return direction === 'ASC' ? cmp : -cmp
    }
    return 0
  })
}

function deriveHeaderMinWidth(header: string | ReactElement): number {
  if (typeof header !== 'string') return 60
  // ~7px per uppercase character + 36px for cell padding and sort icon
  return Math.max(60, header.length * 7 + 36)
}

function mapColumn<TRow, TSummaryRow>(
  col: HarmonyColumn<TRow, TSummaryRow>,
): Column<TRow, TSummaryRow> {
  const renderCell = col.renderCell
  const renderSummaryCell = col.renderSummaryCell
  const renderEditCell = col.renderEditCell

  const minWidth = col.minWidth ?? deriveHeaderMinWidth(col.header)
  const width = typeof col.width === 'number' ? Math.max(col.width, minWidth) : col.width

  return {
    key: col.key,
    name: col.header,
    width,
    minWidth,
    maxWidth: col.maxWidth,
    frozen: col.frozen,
    sortable: col.sortable,
    resizable: col.resizable,
    draggable: col.draggable,
    sortDescendingFirst: col.sortDescendingFirst,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    cellClass: col.cellClass as any,
    headerCellClass: col.headerCellClass,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    summaryCellClass: col.summaryCellClass as any,
    renderCell: renderCell
      ? (props: RenderCellProps<TRow, TSummaryRow>) =>
          renderCell({ row: props.row, rowIdx: props.rowIdx })
      : undefined,
    renderSummaryCell: renderSummaryCell
      ? (props: RenderSummaryCellProps<TSummaryRow, TRow>) =>
          renderSummaryCell({ row: props.row })
      : undefined,
    renderEditCell: renderEditCell
      ? (props: RenderEditCellProps<TRow, TSummaryRow>) =>
          renderEditCell({
            row: props.row,
            rowIdx: props.rowIdx,
            onRowChange: (r, commit) => props.onRowChange(r, commit),
            onClose: commit => props.onClose(commit),
          })
      : undefined,
  }
}

// eslint-disable-next-line react-refresh/only-export-components -- constants co-located with the component that owns them
export const DEFAULT_PAGE_SIZE_OPTIONS  = [15, 30, 50, 100]
export const DEFAULT_PAGE_SIZE          = 15
const DEFAULT_REFRESH_INTERVALS  = [10, 30, 60, 300] // seconds
// Computed per-render from density — see minGridHeight inside the component
// 1px left + 1px right border on the container div — subtracted from fill-column calculations
// to prevent a 2px overflow that would trigger a horizontal scrollbar.
const CONTAINER_BORDER_WIDTH     = 2

function formatInterval(s: number): string {
  if (s < 60) return `${s}s`
  return `${Math.round(s / 60)}m`
}

const DENSITY_ROW_HEIGHT: Record<string, number> = {
  compact:     30,
  comfortable: 38,
  spacious:    46,
}

const DENSITY_TOOLBAR_PADDING: Record<string, string> = {
  compact:     'p-2',
  comfortable: 'p-3',
  spacious:    'p-4',
}

const DENSITY_FOOTER_PADDING: Record<string, string> = {
  compact:     'px-4 py-1.5',
  comfortable: 'px-4 py-2',
  spacious:    'px-4 py-3',
}

// icon-sm button (h-7 = 28px) + footer vertical padding × 2
const DENSITY_FOOTER_MIN_HEIGHT: Record<string, number> = {
  compact:     40,   // 28 + 6×2
  comfortable: 44,   // 28 + 8×2
  spacious:    52,   // 28 + 12×2
}

function useDensity(): string {
  const [density, setDensity] = useState(
    () => document.documentElement.dataset.density ?? 'comfortable'
  )
  useEffect(() => {
    const observer = new MutationObserver(() => {
      setDensity(document.documentElement.dataset.density ?? 'comfortable')
    })
    observer.observe(document.documentElement, { attributes: true, attributeFilter: ['data-density'] })
    return () => observer.disconnect()
  }, [])
  return density
}

// ═══════════════════════════════════════════════════════════════════════════════
// Internal sub-components
// ═══════════════════════════════════════════════════════════════════════════════

interface RefreshControlsProps {
  dataActions: HarmonyDataActions
  liveActive: boolean
}

function RefreshControls({ dataActions, liveActive }: RefreshControlsProps) {
  const ar = dataActions.autoRefresh
  const intervals = ar?.intervalOptions ?? DEFAULT_REFRESH_INTERVALS
  return (
    <>
      <ButtonGroup>
        <Button
          variant="outline"
          size="icon-xs"
          onClick={dataActions.onReload}
          disabled={dataActions.reloading}
          aria-label="Reload"
        >
          <RefreshCw size={12} className={cn(dataActions.reloading && 'animate-spin')} />
        </Button>
        {ar && (
          <>
            <Button
              variant="outline"
              size="xs"
              onClick={() => ar.onToggle(!ar.enabled)}
              aria-label={ar.enabled ? 'Stop auto-refresh' : 'Start auto-refresh'}
              className={cn(
                ar.enabled && 'border-primary bg-primary text-primary-foreground hover:bg-primary/90 hover:text-primary-foreground',
              )}
            >
              <Timer size={12} />
              Auto
            </Button>
            {intervals.length > 1 && (
              <Select
                value={String(ar.interval)}
                onValueChange={v => ar.onIntervalChange?.(Number(v))}
              >
                <SelectTrigger
                  size="sm"
                  className={cn(
                    '!h-6 text-xs min-w-[3.5rem]',
                    ar.enabled && 'border-primary bg-primary/5 text-primary',
                  )}
                >
                  <SelectValue />
                </SelectTrigger>
                <SelectContent position="popper" align="end">
                  {intervals.map(s => (
                    <SelectItem key={s} value={String(s)}>
                      {formatInterval(s)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            )}
          </>
        )}
      </ButtonGroup>
      {liveActive && (
        <div className="inline-flex items-center gap-1 px-1.5 py-0.5 rounded-[var(--radius-sm)] bg-primary/10 border border-primary/30">
          <span className="w-1.5 h-1.5 rounded-full bg-primary animate-pulse" />
          <span className="text-[10px] font-bold text-primary uppercase tracking-wider">
            Live
          </span>
        </div>
      )}
    </>
  )
}

// ═══════════════════════════════════════════════════════════════════════════════
// HarmonyTable
// ═══════════════════════════════════════════════════════════════════════════════

export function HarmonyTable<TRow, TSummaryRow = unknown>({
  rows: rawRows,
  columns: rawColumns,
  rowKeyGetter,

  title,
  description,
  toolbarLeft,
  toolbarRight,

  searchable = true,
  searchPlaceholder = 'Search…',
  searchQuery,
  onSearchChange,
  filterFn,
  filterDefs,
  filterValues: controlledFilterValues,
  onFilterChange,
  searchDebounce = 300,

  sortColumns: controlledSortCols,
  onSortColumnsChange,
  sortFn,

  pagination,

  selectable = false,
  selectedRows: controlledSelectedRows,
  onSelectedRowsChange,
  isRowSelectionDisabled,

  topSummaryRows,
  bottomSummaryRows,
  topSummaryRowsFn,
  bottomSummaryRowsFn,

  noRowsFallback,
  emptyMessage,
  loading = false,
  error,

  onRowsChange,

  // rowHeight: rowHeightProp,        // Disabled: controlled by theme density.
  // headerRowHeight: headerRowHeightProp,
  // summaryRowHeight: summaryRowHeightProp,
  rowClass,

  draggableColumns = false,
  onColumnsReorder,

  onCellClick,
  onCellDoubleClick,

  dataActions,
  selectionActions,
  readonly = false,

  renderRowDetail,
  rowDetailTitle,
  rowDetailVariant = 'dialog',
  rowDetailTrigger = 'dblclick',

  exportable = false,
  exportFilename = 'export.json',

  className,
  gridClassName,
  // direction,            // Disabled: LTR-only.
  // enableVirtualization, // Disabled: default react-data-grid virtualisation is sufficient.
}: HarmonyTableProps<TRow, TSummaryRow>) {

  // ── Density-aware sizing ───────────────────────────────────────────────────
  const density          = useDensity()
  const densityRowHeight = DENSITY_ROW_HEIGHT[density]         ?? 38
  const toolbarPadding   = DENSITY_TOOLBAR_PADDING[density]    ?? 'p-3'
  const footerPadding    = DENSITY_FOOTER_PADDING[density]     ?? 'px-4 py-2'
  const footerMinHeight  = DENSITY_FOOTER_MIN_HEIGHT[density]  ?? 44
  const rowHeight        = densityRowHeight  // prop override disabled; controlled by theme density
  const headerRowHeight  = densityRowHeight
  const summaryRowHeight = densityRowHeight

  // ── Pagination config — always on; prop is for customisation only ──────────
  const paginationCfg = useMemo<HarmonyPagination>(() => {
    return { pageSize: DEFAULT_PAGE_SIZE, pageSizeOptions: DEFAULT_PAGE_SIZE_OPTIONS, ...pagination }
  }, [pagination])

  const isServerPagination = !!paginationCfg?.onPageChange
  const isServerSearch    = !!onSearchChange
  const isServerSort      = !!onSortColumnsChange

  // ── Internal state ─────────────────────────────────────────────────────────
  const [internalSearch,    setInternalSearch]    = useState(searchQuery ?? '')
  const [internalSortCols,  setInternalSortCols]  = useState<SortColumn[]>([])
  const [internalPage,      setInternalPage]      = useState(1)
  const [internalPageSize,  setInternalPageSize]  = useState(paginationCfg.pageSize ?? DEFAULT_PAGE_SIZE)
  const [internalSelected,  setInternalSelected]  = useState<ReadonlySet<string | number>>(new Set())
  const [columnWidths,      setColumnWidths]      = useState<ColumnWidths | undefined>(undefined)
  const [detailRow,         setDetailRow]         = useState<TRow | null>(null)
  const [pageJumpDraft,     setPageJumpDraft]     = useState('1')
  const [internalFilterValues, setInternalFilterValues] = useState<Record<string, string>>(() => {
    const defaults: Record<string, string> = {}
    filterDefs?.forEach(f => { if (f.defaultValue !== undefined) defaults[f.param] = f.defaultValue })
    return defaults
  })
  const searchDebounceRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const containerRef      = useRef<HTMLDivElement>(null)
  const [containerWidth,  setContainerWidth] = useState(0)

  // ── Container width tracking (for fill columns) ────────────────────────────
  // useLayoutEffect fires before the browser paints so containerWidth is set
  // to the real value before react-data-grid ever renders the grid, preventing
  // it from auto-sizing fill columns and storing a stale width via onColumnWidthsChange.
  useLayoutEffect(() => {
    const el = containerRef.current
    if (!el) return
    setContainerWidth(el.getBoundingClientRect().width)
    const ro = new ResizeObserver(([entry]) => setContainerWidth(entry.contentRect.width))
    ro.observe(el)
    return () => ro.disconnect()
  }, [])

  // ── Auto-refresh ───────────────────────────────────────────────────────────
  const arEnabled  = dataActions?.autoRefresh?.enabled
  const arInterval = dataActions?.autoRefresh?.interval
  const onReload   = dataActions?.onReload
  useEffect(() => {
    if (!arEnabled || !onReload) return
    const id = setInterval(onReload, arInterval! * 1000)
    return () => clearInterval(id)
  }, [arEnabled, arInterval, onReload])

  // Sync external searchQuery prop into internal input state (e.g. for reset from outside)
  const [prevSearchQuery, setPrevSearchQuery] = useState(searchQuery)
  if (searchQuery !== prevSearchQuery) {
    setPrevSearchQuery(searchQuery)
    if (searchQuery !== undefined) setInternalSearch(searchQuery)
  }

  // ── Derived values ─────────────────────────────────────────────────────────
  const sortColumns  = (controlledSortCols ?? internalSortCols) as SortColumn[]
  const currentPage  = isServerPagination ? (paginationCfg?.currentPage ?? 1) : internalPage
  const pageSize     = internalPageSize
  const selectedRows = controlledSelectedRows ?? internalSelected

  // ── Data pipeline ──────────────────────────────────────────────────────────
  const processedRows = useMemo(() => {
    let result = rawRows as TRow[]

    if (!isServerSearch && internalSearch.trim()) {
      result = filterFn ? filterFn(result, internalSearch) : simpleFilterFn(result, internalSearch)
    }

    if (!isServerSort && sortColumns.length > 0) {
      const mapped = sortColumns.map(c => ({ columnKey: c.columnKey, direction: c.direction as HarmonySortDirection }))
      result = (sortFn ?? defaultSortFn)(result, mapped)
    }

    return result
  }, [rawRows, internalSearch, isServerSearch, filterFn, sortColumns, isServerSort, sortFn])

  const displayRows = useMemo(() => {
    if (isServerPagination) return processedRows
    const start = (currentPage - 1) * pageSize
    return processedRows.slice(start, start + pageSize)
  }, [processedRows, currentPage, pageSize, isServerPagination])

  const resolvedTopSummaryRows    = useMemo(
    () => topSummaryRowsFn    ? topSummaryRowsFn(processedRows)    : topSummaryRows,
    [topSummaryRowsFn,    topSummaryRows,    processedRows],
  )
  const resolvedBottomSummaryRows = useMemo(
    () => bottomSummaryRowsFn ? bottomSummaryRowsFn(processedRows) : bottomSummaryRows,
    [bottomSummaryRowsFn, bottomSummaryRows, processedRows],
  )

  const totalCount = isServerPagination
    ? (paginationCfg.totalCount ?? rawRows.length)
    : processedRows.length

  const resolvedTotalPages      = paginationCfg.totalPages        ?? Math.max(1, Math.ceil(totalCount / pageSize))
  const resolvedHasPreviousPage = paginationCfg.hasPreviousPage   ?? currentPage > 1
  const resolvedHasNextPage     = paginationCfg.hasNextPage       ?? currentPage < resolvedTotalPages

  // ── Handlers ───────────────────────────────────────────────────────────────
  const handleSearchChange = useCallback((query: string) => {
    setInternalSearch(query)
    if (!isServerPagination) setInternalPage(1)
    if (onSearchChange) {
      if (searchDebounce > 0) {
        if (searchDebounceRef.current) clearTimeout(searchDebounceRef.current)
        searchDebounceRef.current = setTimeout(() => onSearchChange(query), searchDebounce)
      } else {
        onSearchChange(query)
      }
    }
  }, [onSearchChange, isServerPagination, searchDebounce])

  const handleSortChange = useCallback((cols: SortColumn[]) => {
    if (!controlledSortCols) setInternalSortCols(cols)
    if (!isServerPagination) setInternalPage(1)
    onSortColumnsChange?.(cols.map(c => {
      const col = rawColumns.find(rc => rc.key === c.columnKey)
      return {
        columnKey: c.columnKey,
        direction: c.direction as HarmonySortDirection,
        sortParam: col?.sortParam ?? c.columnKey,
      }
    }))
  }, [controlledSortCols, onSortColumnsChange, isServerPagination, rawColumns])

  const handleSelectedRowsChange = useCallback((rows: Set<string | number>) => {
    if (!controlledSelectedRows) setInternalSelected(rows)
    onSelectedRowsChange?.(rows)
  }, [controlledSelectedRows, onSelectedRowsChange])

  const handlePageChange = useCallback((page: number) => {
    const clamped = Math.max(1, Math.min(page, resolvedTotalPages))
    if (!isServerPagination) setInternalPage(clamped)
    paginationCfg.onPageChange?.(clamped)
  }, [isServerPagination, paginationCfg, resolvedTotalPages])

  const handlePageSizeChange = useCallback((size: number) => {
    setInternalPageSize(size)
    setInternalPage(1)
    paginationCfg.onPageSizeChange?.(size)
  }, [paginationCfg])

  const activeFilterValues = controlledFilterValues ?? internalFilterValues

  const handleFilterChange = useCallback((param: string, value: string) => {
    const next: Record<string, string> = value
      ? { ...activeFilterValues, [param]: value }
      : Object.fromEntries(Object.entries(activeFilterValues).filter(([k]) => k !== param))
    if (!controlledFilterValues) setInternalFilterValues(next)
    if (!isServerPagination) setInternalPage(1)
    onFilterChange?.(next)
  }, [activeFilterValues, controlledFilterValues, onFilterChange, isServerPagination])

  const handleBuiltinExport = useCallback(() => {
    const blob = new Blob([JSON.stringify(rawRows, null, 2)], { type: 'application/json' })
    const url  = URL.createObjectURL(blob)
    const a    = document.createElement('a')
    a.href     = url
    a.download = exportFilename
    a.click()
    URL.revokeObjectURL(url)
  }, [rawRows, exportFilename])

  const effectiveSelectable = !readonly && selectable
  const effectiveOnRowsChange = readonly ? undefined : onRowsChange

  // Keep page-jump input in sync when page changes externally (chevrons, page-size change)
  const [prevCurrentPage, setPrevCurrentPage] = useState(currentPage)
  if (currentPage !== prevCurrentPage) {
    setPrevCurrentPage(currentPage)
    setPageJumpDraft(String(currentPage))
  }

  // ── Fill column keys — used by both gridColumns and the width-change handler ─
  const fillColumnKeys = useMemo(
    () => new Set(rawColumns.filter(c => c.fill).map(c => c.key)),
    [rawColumns],
  )

  // Strip fill-column entries before storing so a stale auto-computed width
  // can never override the fill calculation on subsequent renders.
  const handleColumnWidthsChange = useCallback((widths: ColumnWidths) => {
    if (fillColumnKeys.size === 0) { setColumnWidths(widths); return }
    const next = new Map(widths)
    for (const key of fillColumnKeys) next.delete(key)
    setColumnWidths(next as ColumnWidths)
  }, [fillColumnKeys])

  // ── Column mapping ─────────────────────────────────────────────────────────
  const gridColumns = useMemo<Column<TRow, TSummaryRow>[]>(() => {
    const mapped = rawColumns.map(c => mapColumn(c))
    const cols: Column<TRow, TSummaryRow>[] = effectiveSelectable
      ? [{ ...SelectColumn, width: 44, frozen: true } as Column<TRow, TSummaryRow>, ...mapped]
      : mapped

    const fillKeys = new Set(rawColumns.filter(c => c.fill).map(c => c.key))
    if (fillKeys.size === 0 || containerWidth === 0) return cols

    const checkboxWidth = effectiveSelectable ? 44 : 0
    const fixedTotal = rawColumns
      .filter(c => !c.fill && typeof c.width === 'number')
      .reduce((sum, c) => {
        const mw = c.minWidth ?? deriveHeaderMinWidth(c.header)
        return sum + Math.max(c.width as number, mw)
      }, 0)
    const fillWidth = Math.max(80, Math.floor((containerWidth - fixedTotal - checkboxWidth - CONTAINER_BORDER_WIDTH) / fillKeys.size))

    return cols.map(c => fillKeys.has(c.key) ? { ...c, width: fillWidth } : c)
  }, [rawColumns, effectiveSelectable, containerWidth])

  // ── Row class ──────────────────────────────────────────────────────────────
  const resolvedRowClass = useCallback(
    (row: TRow, rowIdx: number) => {
      const custom = rowClass?.(row, rowIdx) ?? ''
      const stripe = rowIdx % 2 !== 0 ? 'rdg-row-odd' : ''
      const clickable = renderRowDetail ? 'cursor-pointer' : ''
      return [custom, stripe, clickable].filter(Boolean).join(' ') || undefined
    },
    [rowClass, renderRowDetail],
  )

  // ── Derived UI flags ───────────────────────────────────────────────────────
  const selectionCount     = selectedRows.size
  const liveActive         = !!(dataActions?.autoRefresh?.enabled)
  const hasRefreshControls = !!(dataActions?.autoRefresh)
  const hasStandaloneReload = !!(dataActions?.onReload && !dataActions?.autoRefresh)
  const hasDataActions      = !!(dataActions?.onCreate || dataActions?.onExport || dataActions?.extra || exportable || hasStandaloneReload)
  const hasFilterRow       = !!(filterDefs && filterDefs.length > 0)
  const refreshInFilterRow = hasFilterRow && hasRefreshControls
  const hasIdentityRow     = !!(title || description || toolbarLeft || toolbarRight || (hasRefreshControls && !refreshInFilterRow))
  const hasCommandBar      = searchable || hasDataActions || (!readonly && !!selectionActions && selectionCount > 0)
  const showPaginationControls = !error && totalCount > pageSize

  const rangeStart  = totalCount === 0 ? 0 : (currentPage - 1) * pageSize + 1
  const rangeEnd    = Math.min(currentPage * pageSize, totalCount)

  // Floor: header + 3 rows — scales automatically with the active density setting
  const minGridHeight = headerRowHeight + 3 * rowHeight + 2

  const gridHeight = Math.max(
    minGridHeight,
    headerRowHeight
      + displayRows.length * rowHeight
      + (resolvedTopSummaryRows?.length ?? 0) * summaryRowHeight
      + (resolvedBottomSummaryRows?.length ?? 0) * summaryRowHeight
      + 2,
  )


  const resolvedDetailTitle = detailRow && rowDetailTitle
    ? typeof rowDetailTitle === 'function' ? rowDetailTitle(detailRow) : rowDetailTitle
    : undefined

  return (
    <>
    <div
      ref={containerRef}
      className={cn(
        'harmony-table flex flex-col border border-border rounded-(--radius-lg) bg-card shadow-sm overflow-hidden',
        className,
      )}
    >
      {/* ── Identity row — title, description, custom flanking content ──────── */}
      {hasIdentityRow && (
        <div className="shrink-0 flex items-center justify-between gap-3 px-4 py-2.5 border-b border-border bg-muted/20">
          <div className="flex items-center gap-3 min-w-0">
            {toolbarLeft}
            {(title || description) && (
              <div className="min-w-0">
                {title && (
                  <h3 className="text-base font-semibold text-foreground leading-tight tracking-tight">
                    {title}
                  </h3>
                )}
                {description && (
                  <p className="text-xs text-muted-foreground mt-0.5 leading-snug">{description}</p>
                )}
              </div>
            )}
          </div>
          {((!refreshInFilterRow && (hasRefreshControls || liveActive)) || toolbarRight) && (
            <div className="flex items-center gap-2 shrink-0">
              {!refreshInFilterRow && hasRefreshControls && dataActions && (
                <RefreshControls dataActions={dataActions} liveActive={liveActive} />
              )}
              {toolbarRight}
            </div>
          )}
        </div>
      )}

      {/* ── Server filters row — above command bar ──────────────────────── */}
      {hasFilterRow && (
        <div className={cn('shrink-0 flex items-center gap-2 border-b border-border bg-muted/10', toolbarPadding)}>
          <div className="flex items-center gap-1 shrink-0">
            <Filter size={11} className="text-muted-foreground" />
            <span className="text-[10px] font-semibold text-muted-foreground uppercase tracking-wider">
              Filters
            </span>
            <HoverCard openDelay={200} closeDelay={100}>
              <HoverCardTrigger asChild>
                <Button variant="ghost" size="icon-xs" aria-label="Filter help">
                  <HelpCircle size={11} className="text-muted-foreground" />
                </Button>
              </HoverCardTrigger>
              <HoverCardContent align="start" className="w-72 p-0 overflow-hidden">
                <div className="px-3.5 py-2.5 border-b border-border bg-muted/40">
                  <p className="text-xs font-semibold text-foreground">Server-side filters</p>
                  <p className="text-[11px] text-muted-foreground mt-0.5">Each change reloads data from the server.</p>
                </div>
                <div className="px-3.5 py-2.5 text-[11px] text-muted-foreground space-y-2">
                  <p>These filters are sent to the server with every request. Selecting a value fetches a fresh, pre-filtered dataset — only matching records are returned.</p>
                  <p className="text-[10px] text-muted-foreground/70">The search box below applies additional filtering on the already-loaded results.</p>
                </div>
              </HoverCardContent>
            </HoverCard>
          </div>
          <div className="h-3.5 w-px bg-border mx-1" />
          <div className="flex items-center gap-2 flex-1 flex-wrap">
            {filterDefs?.map(f => (
              <div key={f.param} className="flex items-center gap-1.5">
                <span className="text-xs text-muted-foreground font-medium whitespace-nowrap">
                  {f.label}
                </span>
                {f.type === 'select' && (
                  <Select
                    value={activeFilterValues[f.param] || '_all_'}
                    onValueChange={v => handleFilterChange(f.param, v === '_all_' ? '' : v)}
                  >
                    <SelectTrigger size="sm" className="w-32">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="_all_">All</SelectItem>
                      {f.options?.map(o => (
                        <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                )}
                {f.type === 'text' && (
                  <input
                    type="text"
                    value={activeFilterValues[f.param] ?? ''}
                    onChange={e => handleFilterChange(f.param, e.target.value)}
                    placeholder={f.placeholder ?? 'Filter…'}
                    className={cn(
                      'text-xs border border-border rounded-[var(--radius-md)] px-2 py-1.5 w-32',
                      'bg-background text-foreground placeholder:text-muted-foreground',
                      'outline-none focus:border-primary focus:ring-2 focus:ring-primary/15',
                    )}
                  />
                )}
                {f.type === 'boolean' && (
                  <Select
                    value={activeFilterValues[f.param] || '_all_'}
                    onValueChange={v => handleFilterChange(f.param, v === '_all_' ? '' : v)}
                  >
                    <SelectTrigger size="sm" className="w-24">
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="_all_">All</SelectItem>
                      <SelectItem value="true">Yes</SelectItem>
                      <SelectItem value="false">No</SelectItem>
                    </SelectContent>
                  </Select>
                )}
              </div>
            ))}
          </div>
          {refreshInFilterRow && dataActions && (
            <div className="flex items-center gap-2 shrink-0 ml-2 pl-2 border-l border-border">
              <RefreshControls dataActions={dataActions} liveActive={liveActive} />
            </div>
          )}
        </div>
      )}

      {/* ── Command bar — search left, data actions / selection strip right ── */}
      {hasCommandBar && (
        <div className={cn('shrink-0 flex items-center justify-between gap-3 border-b border-border bg-muted/20', toolbarPadding)}>

          {/* Left: search */}
          <div className="flex items-center gap-1.5">
            {searchable && (
              <div className="relative">
                <Search
                  size={14}
                  className="absolute left-2.5 top-1/2 -translate-y-1/2 text-muted-foreground pointer-events-none"
                />
                <input
                  type="text"
                  value={internalSearch}
                  placeholder={searchPlaceholder}
                  onChange={e => handleSearchChange(e.target.value)}
                  className={cn(
                    'h-8 pl-8 pr-3 text-sm rounded-[var(--radius-md)] border border-border',
                    'bg-background text-foreground placeholder:text-muted-foreground',
                    'outline-none focus:border-primary focus:ring-2 focus:ring-primary/15',
                    'transition-all duration-150 w-64',
                  )}
                />
              </div>
            )}
          </div>

          {/* Right: selection strip (contextual) OR data action buttons (permanent) */}
          <div className="flex items-center gap-1.5 ml-auto">
            {!readonly && selectionCount > 0 && selectionActions ? (
              <>
                <span className="text-sm font-medium text-primary tabular-nums whitespace-nowrap">
                  {selectionCount} selected
                </span>
                <div className="flex items-center gap-1.5 pl-2 border-l border-border">
                  {selectionActions(selectedRows)}
                </div>
                <Button
                  variant="ghost"
                  size="icon-sm"
                  onClick={() => handleSelectedRowsChange(new Set())}
                  aria-label="Clear selection"
                >
                  <X size={14} />
                </Button>
              </>
            ) : hasDataActions ? (
              <>
                {hasStandaloneReload && (
                  <Button
                    variant="outline"
                    size="icon-xs"
                    onClick={dataActions!.onReload}
                    disabled={dataActions!.reloading}
                    aria-label="Reload"
                  >
                    <RefreshCw size={12} className={cn(dataActions!.reloading && 'animate-spin')} />
                  </Button>
                )}
                {dataActions?.onCreate && (
                  <Button variant="default" size="sm" onClick={dataActions.onCreate}>
                    <Plus size={14} />
                    {dataActions.createLabel ?? 'New'}
                  </Button>
                )}
                {dataActions?.extra}
                {(dataActions?.onExport || exportable) && (
                  <Button
                    variant="default"
                    size="sm"
                    onClick={dataActions?.onExport ?? handleBuiltinExport}
                  >
                    <Download size={14} />
                    {dataActions?.exportLabel ?? 'Export'}
                  </Button>
                )}
              </>
            ) : null}
          </div>
        </div>
      )}

      {/* ── Grid ────────────────────────────────────────────────────────────── */}
      <div className="relative" style={{ height: gridHeight }}>
        {loading && (
          <div className="absolute inset-0 z-10 flex items-center justify-center bg-card/80">
            <div className="flex items-center gap-2 text-muted-foreground text-sm">
              <Loader2 size={15} className="animate-spin text-primary" />
              Loading…
            </div>
          </div>
        )}
        {!loading && !!error && (
          <div
            className="absolute inset-x-0 bottom-0 z-[1] flex flex-col items-center justify-center gap-2 pointer-events-none"
            style={{ top: headerRowHeight }}
          >
            <AlertCircle size={36} className="text-destructive opacity-40" />
            <p className="text-sm font-medium text-destructive">
              {typeof error === 'string'
                ? error
                : error instanceof Error
                  ? error.message
                  : 'Failed to load data'}
            </p>
          </div>
        )}
        {!loading && !error && displayRows.length === 0 && (
          <div
            className="absolute inset-x-0 bottom-0 z-[1] flex flex-col items-center justify-center gap-3 text-muted-foreground pointer-events-none"
            style={{ top: headerRowHeight }}
          >
            {noRowsFallback ?? (
              <>
                <Database size={36} className="opacity-20" />
                <p className="text-sm font-medium">{emptyMessage ?? 'No data to display'}</p>
              </>
            )}
          </div>
        )}

        <DataGrid<TRow, TSummaryRow, string | number>
          columns={gridColumns}
          rows={displayRows}
          rowKeyGetter={rowKeyGetter}

          sortColumns={sortColumns}
          onSortColumnsChange={handleSortChange}

          selectedRows={effectiveSelectable ? (selectedRows as ReadonlySet<string | number>) : undefined}
          onSelectedRowsChange={effectiveSelectable ? handleSelectedRowsChange : undefined}
          isRowSelectionDisabled={effectiveSelectable ? isRowSelectionDisabled : undefined}

          topSummaryRows={resolvedTopSummaryRows}
          bottomSummaryRows={resolvedBottomSummaryRows}

          columnWidths={columnWidths}
          onColumnWidthsChange={handleColumnWidthsChange}

          onColumnsReorder={onColumnsReorder}

          onRowsChange={
            effectiveOnRowsChange
              ? (rows, data) => effectiveOnRowsChange(rows, data.indexes)
              : undefined
          }

          rowHeight={rowHeight}
          headerRowHeight={headerRowHeight}
          summaryRowHeight={summaryRowHeight}

          rowClass={resolvedRowClass}

          onCellClick={
            (onCellClick || (renderRowDetail && rowDetailTrigger === 'click'))
              ? (args) => {
                  if (renderRowDetail && rowDetailTrigger === 'click' && args.column.key !== SelectColumn.key) {
                    setDetailRow(args.row)
                  }
                  onCellClick?.(args.row, args.column.key)
                }
              : undefined
          }
          onCellDoubleClick={
            (onCellDoubleClick || (renderRowDetail && rowDetailTrigger === 'dblclick'))
              ? (args) => {
                  if (renderRowDetail && rowDetailTrigger === 'dblclick' && args.column.key !== SelectColumn.key) {
                    setDetailRow(args.row)
                  }
                  onCellDoubleClick?.(args.row, args.column.key)
                }
              : undefined
          }

          // direction={direction}            // Disabled: LTR-only.
          // enableVirtualization={enableVirtualization} // Disabled: default virtualisation is sufficient.

          defaultColumnOptions={{ resizable: true, sortable: true, draggable: draggableColumns }}

          renderers={{ noRowsFallback: null }}

          className={cn('rdg-harmony', gridClassName)}
          style={{ height: gridHeight }}
        />
      </div>

      {/* ── Footer ──────────────────────────────────────────────────────────── */}
      <div className={cn('shrink-0 flex items-center justify-between border-t border-border bg-muted/20 gap-4', footerPadding)} style={{ minHeight: footerMinHeight }}>

          {/* Status */}
          <div className="flex items-center gap-3 text-xs text-muted-foreground">
            {selectionCount > 0 && (
              <span className="font-semibold text-primary">
                {selectionCount} selected
              </span>
            )}
            {totalCount > 0 && (
              <span className="tabular-nums">
                {rangeStart}–{rangeEnd} of {totalCount}
              </span>
            )}
            {totalCount === 0 && !error && (
              <span>0 rows</span>
            )}
          </div>

          {/* Pagination controls */}
          {showPaginationControls && (
            <div className="flex items-center gap-1">
              {paginationCfg?.pageSizeOptions && (
                <select
                  value={pageSize}
                  onChange={e => handlePageSizeChange(Number(e.target.value))}
                  className={cn(
                    'text-xs border border-border rounded-[var(--radius-md)] px-2 py-1 mr-1',
                    'bg-background text-foreground outline-none focus:border-primary',
                    'cursor-pointer',
                  )}
                >
                  {paginationCfg.pageSizeOptions.map(s => (
                    <option key={s} value={s}>{s} / page</option>
                  ))}
                </select>
              )}

              <div className="h-3.5 w-px bg-border mx-1" />

              <Button
                variant="ghost"
                size="icon-sm"
                disabled={!resolvedHasPreviousPage}
                onClick={() => handlePageChange(1)}
                aria-label="First page"
              >
                <ChevronsLeft size={13} />
              </Button>
              <Button
                variant="ghost"
                size="icon-sm"
                disabled={!resolvedHasPreviousPage}
                onClick={() => handlePageChange(currentPage - 1)}
                aria-label="Previous page"
              >
                <ChevronLeft size={13} />
              </Button>

              <span className="text-xs text-muted-foreground px-2 tabular-nums whitespace-nowrap">
                {currentPage} / {resolvedTotalPages}
              </span>

              <Button
                variant="ghost"
                size="icon-sm"
                disabled={!resolvedHasNextPage}
                onClick={() => handlePageChange(currentPage + 1)}
                aria-label="Next page"
              >
                <ChevronRight size={13} />
              </Button>
              <Button
                variant="ghost"
                size="icon-sm"
                disabled={!resolvedHasNextPage}
                onClick={() => handlePageChange(resolvedTotalPages)}
                aria-label="Last page"
              >
                <ChevronsRight size={13} />
              </Button>

              {resolvedTotalPages > 1 && (
                <div className="flex items-center gap-1.5 ml-2 pl-3 border-l border-border">
                  <span className="text-xs text-muted-foreground whitespace-nowrap">Go to</span>
                  <input
                    type="text"
                    inputMode="numeric"
                    value={pageJumpDraft}
                    onChange={e => setPageJumpDraft(e.target.value)}
                    onBlur={() => {
                      const n = parseInt(pageJumpDraft, 10)
                      handlePageChange(isNaN(n) ? currentPage : n)
                    }}
                    onKeyDown={e => {
                      if (e.key === 'Enter') {
                        const n = parseInt(pageJumpDraft, 10)
                        handlePageChange(isNaN(n) ? currentPage : n)
                        e.currentTarget.blur()
                      }
                    }}
                    className={cn(
                      'w-10 text-center text-xs border border-border rounded-[var(--radius-md)] px-1 py-1',
                      'bg-background text-foreground tabular-nums',
                      'outline-none focus:border-primary focus:ring-2 focus:ring-primary/15',
                    )}
                    aria-label="Go to page"
                  />
                </div>
              )}
            </div>
          )}
        </div>
    </div>

    {/* ── Row detail panel (Sheet or Dialog) ──────────────────────────── */}
    {renderRowDetail !== undefined && detailRow !== null && (() => {
      const onClose = () => setDetailRow(null)
      const content = renderRowDetail(detailRow, onClose)

      if (rowDetailVariant === 'sheet') {
        return (
          <Sheet open onOpenChange={open => { if (!open) setDetailRow(null) }}>
            <SheetContent className="sm:max-w-xl gap-0 p-0 flex flex-col">
              <SheetHeader className="shrink-0 border-b px-4 py-3">
                {resolvedDetailTitle && <SheetTitle>{resolvedDetailTitle}</SheetTitle>}
              </SheetHeader>
              <div className="flex-1 overflow-y-auto px-4 py-4">
                {content}
              </div>
            </SheetContent>
          </Sheet>
        )
      }

      return (
        <Dialog open onOpenChange={open => { if (!open) setDetailRow(null) }}>
          <DialogContent className="sm:max-w-lg max-h-[90vh] overflow-y-auto">
            {resolvedDetailTitle && (
              <DialogHeader>
                <DialogTitle>{resolvedDetailTitle}</DialogTitle>
              </DialogHeader>
            )}
            {content}
          </DialogContent>
        </Dialog>
      )
    })()}
    </>
  )
}
